const followUp = $('Get many rows').first().json;
const checkIn = $('Buscar o crear check-in').first().json;
const messagesRaw = $('Historial de mensajes').all();

const conversationHistory = messagesRaw
  .filter(m => m.json && m.json.id && m.json.content)
  .map(m => ({
    role: m.json.sender === 'owner' ? 'user' : 'assistant',
    content: m.json.content
  }));

const surgeryDate = new Date(followUp.surgery_date);
const now = new Date();
const recoveryDay = Math.ceil((now - surgeryDate) / (1000 * 60 * 60 * 24));

const meds = typeof followUp.medications === 'string'
  ? JSON.parse(followUp.medications)
  : (followUp.medications || []);

const medsText = meds
  .map(m => `- ${m.name} ${m.dose || ''}, ${m.frequency || ''}. ${m.instructions || ''}${m.duration ? ' (' + m.duration + ')' : ''}`.trim())
  .join('\n');

const dynamicContext = [
  '## PACIENTE',
  `- Nombre: ${followUp.patient_name}`,
  `- Especie: ${followUp.species}`,
  `- Raza: ${followUp.breed || 'No especificada'}`,
  `- Peso: ${followUp.weight_kg} kg`,
  '',
  '## CIRUGIA',
  `- Tipo: ${followUp.surgery_type_raw}`,
  `- Fecha: ${followUp.surgery_date}`,
  `- Veterinario: ${followUp.vet_name}`,
  `- Dia de recuperacion: ${recoveryDay} de ${followUp.total_check_in_days}`,
  '',
  '## MEDICACION PRESCRITA',
  medsText,
  '',
  '## INSTRUCCIONES DE ALTA',
  followUp.discharge_instructions
].join('\n');

return [{
  json: {
    dynamic_context: dynamicContext,
    conversation_history: conversationHistory,
    owner_message: $('Webhook').first().json.body.message,
    check_in_id: checkIn.id,
    follow_up_id: followUp.id,
    is_new_check_in: checkIn.is_new
  }
}];

const followUp = $('Get many rows').first().json;
const supabaseUrl = 'https://YOUR_SUPABASE_PROJECT.supabase.co';
const supabaseKey = $vars.SUPABASE_SERVICE_ROLE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: `${supabaseUrl}/rest/v1/check_ins?follow_up_id=eq.${followUp.id}&status=eq.in_progress&limit=1`,
  headers,
  json: true
});

if (existing.length > 0) {
  return [{ json: { ...existing[0], is_new: false } }];
}

const newDay = followUp.current_day + 1;
const created = await this.helpers.httpRequest({
  method: 'POST',
  url: `${supabaseUrl}/rest/v1/check_ins`,
  headers,
  body: {
    follow_up_id: followUp.id,
    day_number: newDay,
    status: 'in_progress',
    started_at: new Date().toISOString()
  },
  json: true
});

return [{ json: { ...created[0], is_new: true } }];

const data = $input.first().json;

const messages = (data.conversation_history || []).concat([
  { role: 'user', content: data.owner_message }
]);

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: [
    { type: 'text', text: data.system_prompt_base, cache_control: { type: 'ephemeral' } },
    { type: 'text', text: data.dynamic_context }
  ],
  messages: messages
};

return [{
  json: {
    body: body,
    check_in_id: data.check_in_id,
    follow_up_id: data.follow_up_id,
    is_new_check_in: data.is_new_check_in
  }
}];

// La respuesta de Anthropic llega directa en $json (HTTP Request sin 'full response').
const resp = $input.first().json;
const payload = resp && resp.content ? resp : ((resp && resp.data) ? resp.data : resp);

let text = '';
if (payload && Array.isArray(payload.content)) {
  text = payload.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

const meta = $('Construir body Claude').first().json;
const webhook = $('Webhook').first().json.body;

let alert_type = null;
if (text.startsWith('[ALERTA:ROJO]')) alert_type = 'red';
else if (text.startsWith('[ALERTA:AMARILLO]')) alert_type = 'yellow';

let is_complete = false;
let risk_level = null;
let summary = null;
let symptoms = [];

const marker = '[CHECK-IN:COMPLETO]';
const idx = text.indexOf(marker);
if (idx !== -1) {
  is_complete = true;
  const after = text.slice(idx + marker.length);
  const jsonMatch = after.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch[0]);
      risk_level = parsed.risk_level || null;
      summary = parsed.summary || null;
      symptoms = parsed.symptoms || [];
    } catch (e) { /* deja los valores por defecto */ }
  }
}

let response_text = text
  .replace(/^\[ALERTA:(ROJO|AMARILLO)\]\s*/, '')
  .replace(/\[CHECK-IN:COMPLETO\][\s\S]*$/, '')
  .trim();

// Markdown -> formato WhatsApp: **negrita** -> *negrita*; encabezados # -> *texto*.
response_text = response_text
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/__(.+?)__/g, '*$1*')
  .replace(/^#{1,6}\s*(.+)$/gm, '*$1*')
  .trim();

if (!risk_level && alert_type) risk_level = alert_type;

return [{
  json: {
    response_text,
    raw_text: text,
    is_complete,
    risk_level,
    summary,
    symptoms,
    alert_type,
    check_in_id: meta.check_in_id,
    follow_up_id: meta.follow_up_id,
    owner_phone: webhook.owner_phone,
    owner_message: webhook.message
  }
}];

const d = $input.first().json;
const supabaseUrl = 'https://YOUR_SUPABASE_PROJECT.supabase.co';
const supabaseKey = $vars.SUPABASE_SERVICE_ROLE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Tabla messages (NOT NULL: check_in_id, direction, sender, content).
// CHECK: direction in {inbound, outbound}; sender in {owner, system}. 'system' se lee como 'assistant'.
const inserted = await this.helpers.httpRequest({
  method: 'POST',
  url: `${supabaseUrl}/rest/v1/messages`,
  headers,
  body: [
    { check_in_id: d.check_in_id, direction: 'inbound',  sender: 'owner',  content: d.owner_message, message_type: 'text' },
    { check_in_id: d.check_in_id, direction: 'outbound', sender: 'system', content: d.response_text, message_type: 'text' }
  ],
  json: true
});

let check_in_updated = false;
let update_error = null;
if (d.is_complete) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${supabaseUrl}/rest/v1/check_ins?id=eq.${d.check_in_id}`,
      headers,
      body: {
        status: 'completed',
        risk_level: d.risk_level || 'green',
        risk_summary: d.summary,
        symptoms: d.symptoms,
        completed_at: new Date().toISOString()
      },
      json: true
    });
    check_in_updated = true;
  } catch (e) {
    update_error = e.message || String(e);
  }
}

return [{
  json: {
    ...d,
    messages_saved: Array.isArray(inserted) ? inserted.length : 0,
    check_in_updated,
    update_error
  }
}];

const d = $input.first().json;
const fu = $('Get many rows').first().json;

const surgeryDate = new Date(fu.surgery_date);
const now = new Date();
const recoveryDay = Math.ceil((now - surgeryDate) / (1000 * 60 * 60 * 24));

const riskMap = { green: 'VERDE', yellow: 'AMARILLO', red: 'ROJO' };
const risk = riskMap[d.risk_level] || (d.risk_level || 'n/d');
const symptoms = Array.isArray(d.symptoms) ? d.symptoms.join(', ') : (d.symptoms || '');
const summary = d.summary || 'Sin resumen';

const email_subject = `[Anicura Lleida] Check-in completado - ${fu.patient_name} (riesgo ${risk})`;
const email_text = [
  'Check-in postoperatorio COMPLETADO - Anicura Lleida',
  '',
  `Paciente: ${fu.patient_name} (${fu.species}${fu.breed ? ', ' + fu.breed : ''}, ${fu.weight_kg} kg)`,
  `Propietario: ${fu.owner_name} - ${d.owner_phone}`,
  `Cirugia: ${fu.surgery_type_raw} - ${fu.vet_name}`,
  `Dia de recuperacion: ${recoveryDay} de ${fu.total_check_in_days}`,
  '',
  `Nivel de riesgo: ${risk}`,
  `Resumen clinico: ${summary}`,
  `Sintomas destacados: ${symptoms || 'ninguno'}`,
  '',
  `check_in_id: ${d.check_in_id}`
].join('\n');

const wa_params = [fu.patient_name, risk, summary, `${fu.owner_name} (${d.owner_phone})`];
const oncall_template = {
  name: 'checkin_completado',
  language: { code: 'es' },
  components: [ { type: 'body', parameters: wa_params.map(t => ({ type: 'text', text: String(t) })) } ]
};

return [{ json: { ...d, email_subject, email_text, oncall_template } }];
